import{_ as t,c as a,b as o,o as n}from"./app-RrIk7Rat.js";const s={};function r(i,e){return n(),a("div",null,e[0]||(e[0]=[o('<h1 id="osdcomponent-component" tabindex="-1"><a class="header-anchor" href="#osdcomponent-component"><span>OsdComponent Component</span></a></h1><p>Displays the OpenSeadragon image viewer with annotation support for zones and measures.</p><hr><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview"><span>Overview</span></a></h2><p>The <code>OsdComponent</code> component:</p><ul><li>Renders an OpenSeadragon viewer for high-resolution images.</li><li>Integrates Annotorious for drawing and managing annotation zones.</li><li>Renders overlays for zones, colored by mdiv.</li><li>Handles selection, creation, update, and hover of annotation zones.</li><li>Reacts to Vuex store changes for pages, zones, mode, and selection.</li></ul><hr><h2 id="layout" tabindex="-1"><a class="header-anchor" href="#layout"><span>Layout</span></a></h2><ul><li><strong>Viewer</strong>: Main image viewer (<code>#osdContainer</code>), full width or reduced if measure list is visible.</li><li><strong>Overlays</strong>: Annotation zones rendered as overlays with labels.</li></ul><hr><h2 id="props" tabindex="-1"><a class="header-anchor" href="#props"><span>Props</span></a></h2><p><em>None</em></p><hr><h2 id="data" tabindex="-1"><a class="header-anchor" href="#data"><span>Data</span></a></h2><table><thead><tr><th>Name</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>colors</td><td>Array</td><td>List of RGBA colors for mdiv overlays</td></tr><tr><td>colorIndex</td><td>Number</td><td>Current color index for assigning colors</td></tr><tr><td>mdivColors</td><td>Object</td><td>Mapping of mdiv indices to assigned colors</td></tr></tbody></table><hr><h2 id="computed-properties" tabindex="-1"><a class="header-anchor" href="#computed-properties"><span>Computed Properties</span></a></h2><table><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>imageArray</td><td>Returns the array of images from the store</td></tr><tr><td>mode</td><td>Returns the current annotation mode from the store</td></tr><tr><td>measureListVisible</td><td>Whether the measure list pane is visible</td></tr></tbody></table><hr><h2 id="methods" tabindex="-1"><a class="header-anchor" href="#methods"><span>Methods</span></a></h2><table><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>getNextColor</td><td>Returns the next color for mdiv overlays</td></tr><tr><td>renderZones</td><td>Renders annotation overlays for all zones on the current page</td></tr><tr><td>toggleSelection</td><td>Enables/disables annotation selection based on mode</td></tr></tbody></table><hr><h2 id="lifecycle-hooks" tabindex="-1"><a class="header-anchor" href="#lifecycle-hooks"><span>Lifecycle Hooks</span></a></h2><ul><li><strong>mounted</strong>: Initializes OpenSeadragon and Annotorious, sets up event listeners, and Vuex watchers.</li><li><strong>beforeUnmount</strong>: Cleans up Vuex watchers.</li></ul><hr><h2 id="example" tabindex="-1"><a class="header-anchor" href="#example"><span>Example</span></a></h2><div class="language-vue line-numbers-mode" data-highlighter="prismjs" data-ext="vue"><pre><code><span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>OsdComponent</span> <span class="token punctuation">/&gt;</span></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div>',27)]))}const l=t(s,[["render",r]]),h=JSON.parse('{"path":"/technical/OsdComponent.html","title":"OsdComponent Component","lang":"en-US","frontmatter":{},"git":{"updatedTime":1756211745000,"contributors":[{"name":"Hizkiel","username":"Hizkiel","email":"hizclick@gmail.com","commits":2,"url":"https://github.com/Hizkiel"}],"changelog":[{"hash":"f154f171982bcbf31ca935ebf59603fd9f7ba544","time":1756211745000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Remove user documentation directory"},{"hash":"addcf634062a696867cd389eb76f27f467f4a69a","time":1747234892000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Correcting the impits based on the pr comments"}]},"filePathRelative":"technical/OsdComponent.md"}');export{l as comp,h as data};
